export type ShowValue = 'body' | 'signature' | 'outline' | 'enclosing' | 'count';
export type ViewValue = 'auto' | 'code' | 'tree' | 'list' | 'context' | 'badge' | 'edit';
export type SizeValue = 'sm' | 'md' | 'lg' | 'xl';

export interface ResolvedDeclarations {
  show: ShowValue;
  view: ViewValue;
  limit?: number;
  title?: string;
  size?: SizeValue;
  gridColumn?: string;
  gridRow?: string;
  collapse?: boolean;
  warnings: string[];
  raw: Record<string, string>;
}

const KNOWN_KEYS = new Set([
  'show', 'view', 'layout', 'multiple', 'location', 'context',
  'limit', 'language', 'title', 'collapse', 'grid-column', 'grid-row', 'size',
]);

const SHOW_TO_VIEW: Record<ShowValue, ViewValue> = {
  body: 'code',
  signature: 'list',
  outline: 'tree',
  enclosing: 'context',
  count: 'badge',
};

const VALID_SHOW = new Set<string>(['body', 'signature', 'outline', 'enclosing', 'count']);
const VALID_VIEW = new Set<string>(['auto', 'code', 'tree', 'list', 'context', 'badge', 'edit']);
const VALID_SIZE = new Set<string>(['sm', 'md', 'lg', 'xl']);

export function resolveDeclarations(raw: Record<string, string>): ResolvedDeclarations {
  const show: ShowValue = VALID_SHOW.has(raw.show) ? (raw.show as ShowValue) : 'body';

  let view: ViewValue;
  if (raw.view && VALID_VIEW.has(raw.view)) {
    view = raw.view as ViewValue;
  } else {
    view = SHOW_TO_VIEW[show];
  }

  const limit = raw.limit ? parseInt(raw.limit, 10) : undefined;
  const title = raw.title || undefined;

  const size: SizeValue | undefined =
    raw.size && VALID_SIZE.has(raw.size) ? (raw.size as SizeValue) : undefined;
  const gridColumn = raw['grid-column'] || undefined;
  const gridRow = raw['grid-row'] || undefined;

  const collapse = raw.collapse === 'true' ? true : raw.collapse === 'false' ? false : undefined;

  const warnings: string[] = [];
  for (const key of Object.keys(raw)) {
    if (!KNOWN_KEYS.has(key)) {
      warnings.push(key);
    }
  }

  return {
    show, view,
    limit: Number.isNaN(limit) ? undefined : limit,
    title, size, gridColumn, gridRow, collapse,
    warnings, raw,
  };
}
