import type { Pane, RuleResult } from './base';

/** Badge pane — renders a large match count with selector/title subtitle. */
export function createBadgePane(id: string): Pane {
  let container: HTMLElement | null = null;

  return {
    id,
    mount(el) {
      container = el;
      container.className = 'pane pane-badge';
    },
    update(result: RuleResult) {
      if (!container) return;
      while (container.firstChild) container.removeChild(container.firstChild);
      const count = document.createElement('div');
      count.className = 'badge-count';
      count.textContent = String(result.matches.length);
      const label = document.createElement('div');
      label.className = 'badge-label';
      label.textContent = result.decls.title || result.rule.selector;
      container.append(count, label);
    },
    destroy() {
      if (container) while (container.firstChild) container.removeChild(container.firstChild);
      container = null;
    },
  };
}
