import type { DuckDBHandle } from '../bootstrap/duckdb';
import type { RegisteredRepo } from '../bootstrap/repo';
import type { PSSRule } from './parser';
import { resolveDeclarations } from './declarations';
import type { AstMatch, RuleResult } from '../widgets/base';

const sqlEscape = (s: string) => s.replace(/'/g, "''");

/**
 * Simple selector to SQL WHERE clause for cached-table fast path.
 * Returns null for complex selectors that need ast_select.
 *
 * Handles #name filters like .func#dispatch_request — these would otherwise
 * fall through to ast_select which has a bug: it matches ALL nodes named
 * dispatch_request (identifiers, calls, function_definitions) instead of
 * filtering by semantic type.
 */
function selectorToSQL(selector: string): string | null {
  const s = selector.trim();
  // Bare selectors
  if (s === '.class:named') return `is_class_definition(semantic_type) AND name IS NOT NULL AND name != ''`;
  if (s === '.func:named') return `is_function_definition(semantic_type) AND name IS NOT NULL AND name != ''`;
  if (s === '.class') return `is_class_definition(semantic_type)`;
  if (s === '.func') return `is_function_definition(semantic_type)`;
  // Workaround for bug #009: modifiers[] is empty for async functions because
  // tree-sitter-python doesn't emit async_function_definition, and async
  // child nodes are syntax-only (filtered from repo_ast). We use a special
  // marker that executeRule handles with a custom query path.
  if (s === '.func:async') return '__ASYNC_WORKAROUND__';
  if (s === '.import') return `type LIKE '%import%'`;

  // .func#name — function definitions with exact name match
  const funcName = s.match(/^\.func#([A-Za-z_][A-Za-z0-9_]*)$/);
  if (funcName) {
    return `is_function_definition(semantic_type) AND name = '${sqlEscape(funcName[1])}'`;
  }
  // .class#name — class definitions with exact name match
  const className = s.match(/^\.class#([A-Za-z_][A-Za-z0-9_]*)$/);
  if (className) {
    return `is_class_definition(semantic_type) AND name = '${sqlEscape(className[1])}'`;
  }
  return null;
}

/** Ensure the repo_ast cache table is warm for the given glob. */
export async function ensureAstCache(
  handle: DuckDBHandle,
  repo: RegisteredRepo,
  fileGlob: string,
  currentCachedGlob: string | null
): Promise<{ parseMs: number; cachedGlob: string }> {
  const fullGlob = `${repo.vfsPrefix}/${fileGlob}`;
  if (currentCachedGlob === fullGlob) return { parseMs: 0, cachedGlob: fullGlob };

  const t0 = performance.now();
  await handle.conn.query(`DROP TABLE IF EXISTS repo_ast`);
  await handle.conn.query(`DROP TABLE IF EXISTS repo_files`);
  // Filter out syntax-only nodes (punctuation, keywords, commas, parens) —
  // these inflate the AST by 5-10x and nobody queries them in practice.
  // If a future selector needs syntax nodes, fall through to full ast_select.
  //
  // We do NOT create a repo_files content table anymore. File contents already
  // live in the VFS (worker side); source text for show:body is read back on
  // demand via db.copyFileToBuffer (see readFileText).
  await handle.conn.query(
    `CREATE TABLE repo_ast AS
     SELECT * FROM read_ast(
       '${sqlEscape(fullGlob)}',
       ignore_errors := true
     )
     WHERE NOT is_syntax_only(flags)`
  );
  return { parseMs: performance.now() - t0, cachedGlob: fullGlob };
}

/**
 * Per-query cache of decoded file text, keyed by VFS path.
 *
 * File bytes live only in the worker's VFS (registerFileBuffer transferred
 * them there), so every peek-needing match reads them back with
 * db.copyFileToBuffer. Caching per query keeps repeated matches in the same
 * file cheap while letting the cache go out of scope — and the strings with
 * it — once the query returns.
 */
type FileTextCache = Map<string, string | null>;

async function readFileText(
  handle: DuckDBHandle,
  filePath: string,
  cache: FileTextCache
): Promise<string | null> {
  const cached = cache.get(filePath);
  if (cached !== undefined) return cached;
  try {
    const bytes = await handle.db.copyFileToBuffer(filePath);
    const text = new TextDecoder().decode(bytes);
    cache.set(filePath, text);
    return text;
  } catch {
    // File not in the VFS (e.g., filtered out by the glob, or the cache
    // outlived the repo). Memoize the miss so we don't retry.
    cache.set(filePath, null);
    return null;
  }
}

/**
 * Extract a slice of source text, reading the file from the VFS on demand.
 * start_line/end_line are 1-indexed inclusive (tree-sitter convention).
 */
async function sliceFromVfs(
  handle: DuckDBHandle,
  cache: FileTextCache,
  filePath: string,
  startLine: number,
  endLine: number
): Promise<string | null> {
  const text = await readFileText(handle, filePath, cache);
  if (!text) return null;
  const lines = text.split('\n');
  const start = Math.max(1, startLine) - 1;
  const end = Math.min(lines.length, endLine);
  if (end <= start) return null;
  const slice = lines.slice(start, end).join('\n');
  return slice === '' ? null : slice;
}

/**
 * Build a SELECT that fetches matches. Peek (source body) is always NULL from
 * SQL — widgets that need source read it back from the VFS in JS.
 */
function buildSelect(
  fromClause: string,
  wherePrefix: string,
  limitClause: string
): string {
  return `
    SELECT m.file_path, m.name, m.type, m.start_line, m.end_line,
           m.qualified_name, NULL AS peek
    FROM ${fromClause} m
    ${wherePrefix}
    ORDER BY m.file_path, m.start_line ${limitClause}
  `;
}

/** Execute a single PSS rule against the cached repo_ast table. */
export async function executeRule(
  handle: DuckDBHandle,
  repo: RegisteredRepo,
  rule: PSSRule,
  fileGlob: string,
  fileTextCache: FileTextCache
): Promise<RuleResult> {
  const decls = resolveDeclarations(rule.declarations);
  const whereClause = selectorToSQL(rule.selector);
  const limitClause = decls.limit ? `LIMIT ${decls.limit}` : '';
  const needsPeek = decls.view === 'code' || decls.view === 'context' || decls.view === 'edit';
  // For badges, we only need the count — running the full query and
  // serializing thousands of rows to JS just to call .length is wasteful.
  const countOnly = decls.view === 'badge';

  // Bug #009 workaround: async child nodes are syntax-only and filtered from
  // repo_ast, so we scan the unfiltered read_ast for 'async' type nodes and
  // match their parent_id to function definitions in the cached table.
  const isAsyncWorkaround = whereClause === '__ASYNC_WORKAROUND__';
  const asyncWhere = isAsyncWorkaround
    ? `is_function_definition(m.semantic_type) AND m.node_id IN (
         SELECT parent_id FROM read_ast('${sqlEscape(`${repo.vfsPrefix}/${fileGlob}`)}', ignore_errors := true)
         WHERE type = 'async'
       )`
    : '';

  let sql: string;
  if (isAsyncWorkaround) {
    if (countOnly) {
      sql = `SELECT COUNT(*)::BIGINT AS n FROM repo_ast m WHERE ${asyncWhere}`;
    } else {
      sql = buildSelect('repo_ast', `WHERE ${asyncWhere}`, limitClause);
    }
  } else if (countOnly && whereClause) {
    // Fast path for badges on the cached table.
    const prefixed = whereClause.replace(
      /\b(semantic_type|name|type|modifiers|start_line|end_line|file_path|qualified_name)\b/g,
      'm.$1'
    );
    sql = `SELECT COUNT(*)::BIGINT AS n FROM repo_ast m WHERE ${prefixed}`;
  } else if (countOnly) {
    // Badge with a complex selector — still cheaper to count than materialize.
    const fullGlob = `${repo.vfsPrefix}/${fileGlob}`;
    sql = `SELECT COUNT(*)::BIGINT AS n FROM ast_select(
      '${sqlEscape(fullGlob)}', '${sqlEscape(rule.selector)}'
    )`;
  } else if (whereClause) {
    const prefixed = whereClause.replace(
      /\b(semantic_type|name|type|modifiers|start_line|end_line|file_path|qualified_name)\b/g,
      'm.$1'
    );
    sql = buildSelect('repo_ast', `WHERE ${prefixed}`, limitClause);
  } else {
    const fullGlob = `${repo.vfsPrefix}/${fileGlob}`;
    const astSelectCall = `ast_select('${sqlEscape(fullGlob)}', '${sqlEscape(rule.selector)}')`;
    sql = buildSelect(astSelectCall, '', limitClause);
  }

  const t0 = performance.now();
  const result = await handle.conn.query(sql);
  const queryMs = performance.now() - t0;

  let matches: AstMatch[];
  if (countOnly) {
    // The badge widget only reads matches.length, so we fabricate a sparse
    // array of the right size without materializing real match objects.
    const n = Number((result.toArray()[0] as { n: number | bigint }).n);
    matches = new Array(n);
  } else {
    matches = result.toArray().map((r) => {
      const out: Record<string, unknown> = {};
      for (const [k, v] of Object.entries(r)) {
        out[k] = typeof v === 'bigint' ? Number(v) : v;
      }
      return out as unknown as AstMatch;
    });
    // Populate peek from the VFS (only for views that actually need it).
    // Sequential to share the per-query cache without racing on duplicate reads.
    if (needsPeek) {
      for (const m of matches) {
        m.peek = await sliceFromVfs(
          handle,
          fileTextCache,
          m.file_path,
          m.start_line,
          m.end_line
        );
      }
    }
  }

  return { rule, decls, matches, queryMs };
}

/** Execute all rules in a PSS document. */
export async function executeAllRules(
  handle: DuckDBHandle,
  repo: RegisteredRepo,
  rules: PSSRule[],
  fileGlob: string
): Promise<RuleResult[]> {
  // Shared across rules in one run so two panes looking at the same file
  // decode it once instead of per rule.
  const fileTextCache: FileTextCache = new Map();
  const results: RuleResult[] = [];
  for (const rule of rules) {
    results.push(await executeRule(handle, repo, rule, fileGlob, fileTextCache));
  }
  return results;
}
