import type { Pane } from './base';
import type { ViewValue } from '../pss/declarations';
import { createCodePane } from './code';
import { createListPane } from './list';
import { createBadgePane } from './badge';
import { createTreePane } from './tree';
import { createContextPane } from './context';
import { createEditPane } from './edit';

/** Create a pane widget based on the resolved view type. */
export function createPane(id: string, view: ViewValue): Pane {
  switch (view) {
    case 'badge':   return createBadgePane(id);
    case 'list':    return createListPane(id);
    case 'tree':    return createTreePane(id);
    case 'context': return createContextPane(id);
    case 'edit':    return createEditPane(id);
    case 'code':
    case 'auto':
    default:
      return createCodePane(id);
  }
}
