import { initDuckDB, loadSittingDuck, type DuckDBHandle } from './bootstrap/duckdb';
import {
  parseRepoUrl,
  fetchAndExtractRepo,
  extractTarballEntries,
  extractZipEntries,
  registerEntries,
  registerRepo,
  type RegisteredRepo,
  type RepoEntry,
} from './bootstrap/repo';
import { mountChrome, BUNDLED_DEMOS, GITHUB_DEMOS, THEMES, type Demo, type ThemeName } from './ui/chrome';
import { parsePSS } from './pss/parser';
import { ensureAstCache, executeAllRules } from './pss/executor';
import { createPane } from './widgets/factory';
import type { Pane, RuleResult } from './widgets/base';
import type { ResolvedDeclarations, SizeValue } from './pss/declarations';

const DEMO_MODE = !!import.meta.env.VITE_DEMO;
const app = document.getElementById('app')!;
const chrome = mountChrome(app);

const SIZE_TO_SPAN: Record<SizeValue, { col: string; row: string }> = {
  sm: { col: 'span 3', row: 'span 1' },
  md: { col: 'span 4', row: 'span 2' },
  lg: { col: 'span 6', row: 'span 3' },
  xl: { col: 'span 12', row: 'span 4' },
};

function attachCollapseToggle(
  paneEl: HTMLElement,
  decls: ResolvedDeclarations,
  isFirstMount: boolean
): void {
  const title = paneEl.querySelector('.pane-title') as HTMLElement | null;
  if (!title) return;

  const toggle = document.createElement('span');
  toggle.className = 'pane-collapse-toggle';
  toggle.textContent = '▾';
  title.prepend(toggle);

  if (isFirstMount && decls.collapse === true) {
    paneEl.classList.add('pane-collapsed');
  }

  title.addEventListener('click', () => {
    paneEl.classList.toggle('pane-collapsed');
  });
}

function applyGridPlacement(el: HTMLElement, decls: ResolvedDeclarations): void {
  if (decls.gridColumn) {
    el.style.gridColumn = decls.gridColumn;
  } else if (decls.size) {
    el.style.gridColumn = SIZE_TO_SPAN[decls.size].col;
  } else {
    el.style.gridColumn = '1 / -1';
  }
  if (decls.gridRow) {
    el.style.gridRow = decls.gridRow;
  } else if (decls.size) {
    el.style.gridRow = SIZE_TO_SPAN[decls.size].row;
  } else {
    el.style.gridRow = '';
  }
}

let handle: (DuckDBHandle & { platform: string }) | null = null;
let currentRepo: RegisteredRepo | null = null;
let currentRegisteredGlob: string | null = null;
let currentRepoKey: string | null = null;
let cachedGlob: string | null = null;

const activePanes = new Map<string, { pane: Pane; el: HTMLElement }>();

async function boot() {
  try {
    chrome.setStatus('Booting DuckDB...');
    handle = await initDuckDB();
    chrome.setStatus('Loading sitting_duck extension from community CDN...');
    await loadSittingDuck(handle);
    chrome.setStatus(
      DEMO_MODE
        ? 'Ready. Pick a demo or upload an archive.'
        : 'Ready. Load a repo, then type PSS rules.',
      'ok'
    );
    chrome.setBusy(false);
    chrome.showAlpha();
  } catch (err) {
    chrome.setStatus(`Boot failed: ${String(err)}`, 'error');
    console.error(err);
  }
}

// ── Repo loading (shared between GitHub fetch, bundled tarball, and upload) ──

async function loadEntries(
  repoKey: string,
  entries: RepoEntry[],
  fileGlob: string
): Promise<{ fetchMs: number; parseMs: number; cached: boolean }> {
  if (!handle) return { fetchMs: 0, parseMs: 0, cached: false };

  const needsRegister =
    !currentRepo ||
    currentRepoKey !== repoKey ||
    currentRegisteredGlob !== fileGlob;

  let fetchMs = 0;
  let cached = false;

  if (needsRegister) {
    const t0 = performance.now();
    chrome.setStatus(`Registering ${entries.length} files into VFS...`);
    currentRepo = await registerEntries(handle, repoKey, entries);

    currentRepoKey = repoKey;
    currentRegisteredGlob = fileGlob;
    fetchMs = performance.now() - t0;
    cachedGlob = null;
  } else {
    cached = true;
  }

  if (!currentRepo) throw new Error('currentRepo missing after register');
  chrome.setStatus(`Parsing ${fileGlob} into AST cache...`);
  const cacheResult = await ensureAstCache(handle, currentRepo, fileGlob, cachedGlob);
  cachedGlob = cacheResult.cachedGlob;
  return { fetchMs, parseMs: cacheResult.parseMs, cached };
}

/** Dev mode: fetch from GitHub via proxy. */
async function loadRepo(
  repoInput: string,
  fileGlob: string
): Promise<{ fetchMs: number; parseMs: number; cached: boolean }> {
  if (!handle) return { fetchMs: 0, parseMs: 0, cached: false };
  const parsed = parseRepoUrl(repoInput);
  const repoKey = `${parsed.owner}/${parsed.repo}`;

  if (currentRepoKey !== repoKey || currentRegisteredGlob !== fileGlob) {
    chrome.setStatus(`Fetching tarball for ${repoKey}...`);
    const t0 = performance.now();
    const entries = await fetchAndExtractRepo(parsed, fileGlob);
    const fetchMs = performance.now() - t0;
    chrome.setStatus(`Got ${entries.length} files; registering...`);
    currentRepo = await registerRepo(handle, parsed, entries);

    currentRepoKey = repoKey;
    currentRegisteredGlob = fileGlob;
    cachedGlob = null;

    chrome.setStatus(`Parsing ${fileGlob} into AST cache...`);
    const cacheResult = await ensureAstCache(handle, currentRepo, fileGlob, cachedGlob);
    cachedGlob = cacheResult.cachedGlob;
    return { fetchMs, parseMs: cacheResult.parseMs, cached: false };
  }

  const cacheResult = await ensureAstCache(handle, currentRepo!, fileGlob, cachedGlob);
  cachedGlob = cacheResult.cachedGlob;
  return { fetchMs: 0, parseMs: cacheResult.parseMs, cached: true };
}

/** Load a bundled demo tarball from a relative URL. */
async function loadBundledTarball(
  tarballUrl: string,
  repoKey: string,
  fileGlob: string
): Promise<{ fetchMs: number; parseMs: number; cached: boolean }> {
  if (!handle) return { fetchMs: 0, parseMs: 0, cached: false };

  if (currentRepoKey === repoKey && currentRegisteredGlob === fileGlob) {
    const cacheResult = await ensureAstCache(handle, currentRepo!, fileGlob, cachedGlob);
    cachedGlob = cacheResult.cachedGlob;
    return { fetchMs: 0, parseMs: cacheResult.parseMs, cached: true };
  }

  chrome.setStatus(`Loading demo ${repoKey}...`);
  const t0 = performance.now();
  const res = await fetch(tarballUrl);
  if (!res.ok) throw new Error(`Failed to fetch demo tarball: HTTP ${res.status}`);
  const gz = new Uint8Array(await res.arrayBuffer());
  const entries = extractTarballEntries(gz, fileGlob);
  const fetchMs = performance.now() - t0;
  return loadEntries(repoKey, entries, fileGlob).then((r) => ({
    ...r,
    fetchMs,
  }));
}

/** Load from user-uploaded file (tar.gz or zip). */
async function loadUploadedFile(
  file: File,
  fileGlob: string
): Promise<{ fetchMs: number; parseMs: number; cached: boolean }> {
  if (!handle) return { fetchMs: 0, parseMs: 0, cached: false };

  const repoKey = `upload/${file.name.replace(/\.(tar\.gz|tgz|zip)$/i, '')}`;
  chrome.setStatus(`Reading ${file.name}...`);
  const t0 = performance.now();
  const buf = await file.arrayBuffer();

  let entries: RepoEntry[];
  const lower = file.name.toLowerCase();
  if (lower.endsWith('.zip')) {
    entries = await extractZipEntries(buf, fileGlob);
  } else {
    entries = extractTarballEntries(new Uint8Array(buf), fileGlob);
  }

  const fetchMs = performance.now() - t0;
  chrome.setStatus(`Got ${entries.length} files from upload; registering...`);
  return loadEntries(repoKey, entries, fileGlob).then((r) => ({
    ...r,
    fetchMs,
  }));
}

// ── PSS execution ───────────────────────────────────────────────────

async function runPSS(pssText: string, fileGlob: string): Promise<RuleResult[]> {
  if (!handle || !currentRepo) return [];
  const rules = parsePSS(pssText);
  if (rules.length === 0) {
    chrome.setStatus('No rules in PSS document.', 'info');
    return [];
  }
  chrome.setStatus(`Executing ${rules.length} rule${rules.length === 1 ? '' : 's'}...`);
  const results = await executeAllRules(handle, currentRepo, rules, fileGlob);
  return results;
}

// ── Pane rendering ──────────────────────────────────────────────────

function renderPanes(results: RuleResult[]) {
  const newIds = new Set(results.map((r) => r.rule.id));

  for (const [id, entry] of activePanes.entries()) {
    if (!newIds.has(id)) {
      entry.pane.destroy();
      entry.el.remove();
      activePanes.delete(id);
    }
  }

  for (const result of results) {
    const id = result.rule.id;
    let entry = activePanes.get(id);
    const isFirstMount = !entry;
    if (!entry) {
      const paneEl = document.createElement('div');
      const pane = createPane(id, result.decls.view);
      pane.mount(paneEl);
      chrome.paneContainer.append(paneEl);
      entry = { pane, el: paneEl };
      activePanes.set(id, entry);
    }
    entry.pane.update(result);
    applyGridPlacement(entry.el, result.decls);
    attachCollapseToggle(entry.el, result.decls, isFirstMount);
  }

  for (const result of results) {
    const entry = activePanes.get(result.rule.id);
    if (entry) chrome.paneContainer.append(entry.el);
  }
}

// ── Event handlers ──────────────────────────────────────────────────

let lastFetchMs: number | undefined;
let lastParseMs = 0;
let lastCached = false;

async function onLoad() {
  if (!handle) return;
  chrome.setBusy(true);
  try {
    const repo = chrome.inputEl.value;
    const fileGlob = chrome.globEl.value || '**/*.py';
    const { fetchMs, parseMs, cached } = await loadRepo(repo, fileGlob);
    chrome.setStatus(
      `Repo loaded. ${currentRepo?.fileCount ?? 0} files. ${
        fetchMs ? `Fetch ${fetchMs.toFixed(0)}ms, ` : ''
      }parse ${parseMs.toFixed(0)}ms.`,
      'ok'
    );
    lastFetchMs = fetchMs || undefined;
    lastParseMs = parseMs;
    lastCached = cached;
    chrome.setRepoName(currentRepoKey ?? 'no repo');
  } catch (err) {
    chrome.setStatus(`Load failed: ${String(err)}`, 'error');
    console.error(err);
  } finally {
    chrome.setBusy(false);
  }
}

async function onRun() {
  if (!handle || !currentRepo) {
    chrome.setStatus('Load a repo first.', 'error');
    return;
  }
  chrome.setBusy(true);
  try {
    const fileGlob = chrome.globEl.value || '**/*.py';
    const pssText = chrome.sourceTextarea.value;
    const t0 = performance.now();
    const results = await runPSS(pssText, fileGlob);
    const totalQueryMs = performance.now() - t0;

    renderPanes(results);

    const totalMatches = results.reduce((s, r) => s + r.matches.length, 0);
    const allFiles = new Set<string>();
    for (const r of results) {
      if (r.decls.view === 'badge') continue;
      for (const m of r.matches) allFiles.add(m.file_path);
    }

    chrome.setSummary({
      ruleCount: results.length,
      totalMatches,
      totalFiles: allFiles.size,
      totalQueryMs,
      parseMs: lastParseMs > 0 ? lastParseMs : undefined,
      fetchMs: lastFetchMs,
      cached: lastCached,
    });
    chrome.setStatus(
      `Done. ${results.length} rule${results.length === 1 ? '' : 's'}, ${totalMatches} total matches in ${totalQueryMs.toFixed(0)}ms.`,
      'ok'
    );
    lastFetchMs = undefined;
    lastParseMs = 0;
  } catch (err) {
    chrome.setStatus(`Run failed: ${String(err)}`, 'error');
    console.error(err);
  } finally {
    chrome.setBusy(false);
  }
}

async function onDemo(demo: Demo) {
  chrome.globEl.value = demo.glob;
  chrome.sourceTextarea.value = demo.pss;
  chrome.setBusy(true);
  try {
    let result: { fetchMs: number; parseMs: number; cached: boolean };
    if (demo.tarball) {
      const repoKey = `demo/${demo.tarball.replace(/^demos\//, '').replace(/\.tar\.gz$/, '')}`;
      result = await loadBundledTarball(demo.tarball, repoKey, demo.glob);
    } else if (demo.repo) {
      chrome.inputEl.value = demo.repo;
      result = await loadRepo(demo.repo, demo.glob);
    } else {
      throw new Error('Demo has neither tarball nor repo');
    }
    lastFetchMs = result.fetchMs || undefined;
    lastParseMs = result.parseMs;
    lastCached = result.cached;
    chrome.setRepoName(currentRepoKey ?? 'no repo');
  } catch (err) {
    chrome.setStatus(`Load failed: ${String(err)}`, 'error');
    console.error(err);
    chrome.setBusy(false);
    return;
  }
  chrome.setBusy(false);
  await onRun();
}

async function onUpload(file: File) {
  chrome.setBusy(true);
  try {
    const fileGlob = chrome.globEl.value || '**/*';
    const result = await loadUploadedFile(file, fileGlob);
    lastFetchMs = result.fetchMs || undefined;
    lastParseMs = result.parseMs;
    lastCached = result.cached;
    chrome.setRepoName(currentRepoKey ?? file.name);
    chrome.setStatus(
      `Uploaded ${file.name}. ${currentRepo?.fileCount ?? 0} files.`,
      'ok'
    );
  } catch (err) {
    chrome.setStatus(`Upload failed: ${String(err)}`, 'error');
    console.error(err);
  } finally {
    chrome.setBusy(false);
  }
}

// ── Command dispatch ────────────────────────────────────────────────

async function handleCommand(cmd: string, args: string) {
  switch (cmd) {
    case 'run':
    case 'r':
      await onRun();
      break;

    case 'pss': {
      if (args) {
        chrome.sourceTextarea.value = args;
      }
      await onRun();
      break;
    }

    case 'sql': {
      if (!handle || !currentRepo) {
        chrome.setStatus('Load a repo first.', 'error');
        return;
      }
      if (!args) {
        chrome.setStatus(':sql requires a query', 'error');
        return;
      }
      chrome.setBusy(true);
      try {
        const t0 = performance.now();
        const result = await handle.conn.query(args);
        const ms = performance.now() - t0;
        const rows = result.toArray();
        chrome.setStatus(`SQL: ${rows.length} row${rows.length === 1 ? '' : 's'} in ${ms.toFixed(0)}ms`, 'ok');
        console.table(rows.map((r) => {
          const out: Record<string, unknown> = {};
          for (const [k, v] of Object.entries(r)) {
            out[k] = typeof v === 'bigint' ? Number(v) : v;
          }
          return out;
        }));
      } catch (err) {
        chrome.setStatus(`SQL error: ${String(err)}`, 'error');
      } finally {
        chrome.setBusy(false);
      }
      break;
    }

    case 'load': {
      if (!args) {
        chrome.setStatus(':load requires a repo (owner/repo) or demo name', 'error');
        return;
      }
      // Check if args match a demo name
      const allDemos = DEMO_MODE ? BUNDLED_DEMOS : GITHUB_DEMOS;
      const demo = allDemos.find(
        (d) => d.label.toLowerCase().startsWith(args.toLowerCase())
      );
      if (demo) {
        await onDemo(demo);
      } else {
        chrome.inputEl.value = args;
        await onLoad();
      }
      break;
    }

    case 'upload':
      // Trigger the file dialog programmatically
      document.querySelector<HTMLInputElement>('input[type="file"]')?.click();
      break;

    case 'glob': {
      if (args) chrome.globEl.value = args;
      chrome.setStatus(`Glob: ${chrome.globEl.value}`, 'info');
      break;
    }

    case 'theme':
    case 't': {
      if (!args) {
        // Cycle to next theme
        const next = THEMES[(THEMES.indexOf(chrome.currentTheme()) + 1) % THEMES.length];
        chrome.setTheme(next);
        chrome.setStatus(`Theme: ${next}`, 'info');
      } else {
        const name = args as ThemeName;
        if (THEMES.includes(name)) {
          chrome.setTheme(name);
          chrome.setStatus(`Theme: ${name}`, 'info');
        } else {
          chrome.setStatus(`Unknown theme: ${args}. Available: ${THEMES.join(', ')}`, 'error');
        }
      }
      break;
    }

    case 'alpha':
      chrome.showAlpha();
      break;

    case 'help':
    case 'h':
      chrome.showHelp();
      break;

    default:
      chrome.setStatus(`Unknown command: ${cmd}. Type :help for available commands.`, 'error');
  }
}

// ── Wire up ─────────────────────────────────────────────────────────

chrome.onDemo = onDemo;
chrome.onUpload = onUpload;
chrome.onCommand = handleCommand;
chrome.loadButtonEl.addEventListener('click', onLoad);
chrome.runButtonEl.addEventListener('click', onRun);
chrome.inputEl.addEventListener('keydown', (ev) => {
  if (ev.key === 'Enter' && !chrome.loadButtonEl.disabled) onLoad();
});
chrome.globEl.addEventListener('keydown', (ev) => {
  if (ev.key === 'Enter' && !chrome.loadButtonEl.disabled) onLoad();
});
chrome.sourceTextarea.addEventListener('keydown', (ev) => {
  if (ev.key === 'Enter' && (ev.ctrlKey || ev.metaKey) && !chrome.runButtonEl.disabled) {
    ev.preventDefault();
    onRun();
  }
});

boot();
