import type { PSSRule } from '../pss/parser';
import type { ResolvedDeclarations } from '../pss/declarations';

/** A single AST match returned from a query. */
export interface AstMatch {
  file_path: string;
  name: string | null;
  type: string;
  start_line: number;
  end_line: number;
  peek: string | null;
  /** Scope-qualified name (e.g., "ClassName.methodName") for tree grouping. */
  qualified_name: string | null;
  [key: string]: unknown;
}

/** Location key for cross-pane sync (v2). */
export interface LocationKey {
  filePath: string;
  startLine: number;
  startColumn: number;
  endLine: number;
  endColumn: number;
}

/** Result of executing a single PSS rule. */
export interface RuleResult {
  rule: PSSRule;
  decls: ResolvedDeclarations;
  matches: AstMatch[];
  queryMs: number;
}

/** Interface all pane widgets implement. */
export interface Pane {
  readonly id: string;
  mount(container: HTMLElement): void;
  update(result: RuleResult): void;
  destroy(): void;
}

/** Strip the VFS prefix (owner/repo/) from a file path for display. */
export function displayPath(filePath: string): string {
  const parts = filePath.split('/');
  return parts.length > 2 ? parts.slice(2).join('/') : filePath;
}
