import type { Pane, AstMatch, RuleResult } from './base';
import { displayPath } from './base';

/**
 * Extract the "group key" — the class path (if any) from qualified_name.
 * 'Flask.dispatch_request' → 'Flask'
 * 'dispatch_request' → '' (module-level)
 */
function groupKey(match: AstMatch): string {
  if (!match.qualified_name) return '';
  // qualified_name may arrive as a non-string (e.g. a DuckDB typed object);
  // coerce to string defensively before doing string operations.
  const qn = String(match.qualified_name);
  const name = match.name ?? '';
  if (qn === name) return '';
  if (qn.endsWith('.' + name)) return qn.slice(0, -(name.length + 1));
  return qn;
}

/** Tree pane — matches grouped by file → enclosing class → item. */
export function createTreePane(id: string): Pane {
  let container: HTMLElement | null = null;

  return {
    id,
    mount(el) {
      container = el;
      container.className = 'pane pane-tree';
    },
    update(result: RuleResult) {
      if (!container) return;
      while (container.firstChild) container.removeChild(container.firstChild);

      const title = document.createElement('div');
      title.className = 'pane-title';
      title.textContent = result.decls.title || result.rule.selector;
      container.append(title);

      if (result.matches.length === 0) {
        const empty = document.createElement('div');
        empty.className = 'pane-empty';
        empty.textContent = 'No matches.';
        container.append(empty);
        return;
      }

      const limit = result.decls.limit ?? result.matches.length;
      const matches = result.matches.slice(0, limit);

      const byFile = new Map<string, Map<string, AstMatch[]>>();
      for (const m of matches) {
        const fk = m.file_path;
        const gk = groupKey(m);
        let fileMap = byFile.get(fk);
        if (!fileMap) {
          fileMap = new Map<string, AstMatch[]>();
          byFile.set(fk, fileMap);
        }
        let arr = fileMap.get(gk);
        if (!arr) {
          arr = [];
          fileMap.set(gk, arr);
        }
        arr.push(m);
      }

      const sortedFiles = [...byFile.keys()].sort();
      for (const filePath of sortedFiles) {
        const fileDetails = document.createElement('details');
        fileDetails.className = 'tree-file';
        fileDetails.open = true;

        const fileSummary = document.createElement('summary');
        fileSummary.className = 'tree-file-header';
        fileSummary.textContent = displayPath(filePath);
        fileDetails.append(fileSummary);

        const groups = byFile.get(filePath)!;
        const sortedGroups = [...groups.keys()].sort((a, b) => {
          if (a === '' && b !== '') return -1;
          if (b === '' && a !== '') return 1;
          return a.localeCompare(b);
        });

        for (const gk of sortedGroups) {
          const items = groups.get(gk)!;
          if (gk === '') {
            for (const m of items) fileDetails.append(renderLeaf(m));
          } else {
            const groupDetails = document.createElement('details');
            groupDetails.className = 'tree-group';
            groupDetails.open = true;

            const groupSummary = document.createElement('summary');
            groupSummary.className = 'tree-group-header';
            groupSummary.textContent = gk;
            groupDetails.append(groupSummary);

            for (const m of items) groupDetails.append(renderLeaf(m));
            fileDetails.append(groupDetails);
          }
        }

        container.append(fileDetails);
      }
    },
    destroy() {
      if (container) while (container.firstChild) container.removeChild(container.firstChild);
      container = null;
    },
  };
}

function renderLeaf(match: AstMatch): HTMLElement {
  const leaf = document.createElement('div');
  leaf.className = 'tree-leaf';

  const nameSpan = document.createElement('span');
  nameSpan.className = 'tree-leaf-name';
  nameSpan.textContent = match.name ?? match.type;

  const lineSpan = document.createElement('span');
  lineSpan.className = 'tree-leaf-line';
  lineSpan.textContent = ` · L${match.start_line}`;

  leaf.append(nameSpan, lineSpan);
  return leaf;
}
