/**
 * Minimal ustar / POSIX tar reader for browser use.
 *
 * Supports only what GitHub's `/tarball` endpoint produces:
 *   - regular files (type '0' or '\0')
 *   - long names via the GNU 'L' longlink extension (paths > 100 chars)
 *   - directories, which are skipped
 *
 * Does NOT support: symlinks, hardlinks, sparse files, pax headers, or
 * any type other than the above. For our purposes those would be skipped
 * silently anyway.
 */

export interface TarEntry {
  name: string;
  bytes: Uint8Array;
}

const BLOCK_SIZE = 512;

/** Parse an octal ASCII field into a number. Trailing nulls/spaces tolerated. */
function readOctal(buf: Uint8Array, offset: number, length: number): number {
  let end = offset + length;
  while (end > offset) {
    const c = buf[end - 1];
    if (c !== 0 && c !== 32) break;
    end--;
  }
  let n = 0;
  for (let i = offset; i < end; i++) {
    const c = buf[i];
    if (c < 48 || c > 55) continue; // skip non-octal chars defensively
    n = n * 8 + (c - 48);
  }
  return n;
}

/** Parse a NUL-terminated ASCII string field. */
function readString(buf: Uint8Array, offset: number, length: number): string {
  let end = offset;
  const limit = offset + length;
  while (end < limit && buf[end] !== 0) end++;
  return new TextDecoder('utf-8').decode(buf.subarray(offset, end));
}

export function untar(buf: Uint8Array): TarEntry[] {
  const entries: TarEntry[] = [];
  let offset = 0;
  let longName: string | null = null;

  while (offset + BLOCK_SIZE <= buf.length) {
    // A header that's all zeros marks end-of-archive.
    let allZero = true;
    for (let i = 0; i < BLOCK_SIZE; i++) {
      if (buf[offset + i] !== 0) {
        allZero = false;
        break;
      }
    }
    if (allZero) break;

    const name = readString(buf, offset, 100);
    const size = readOctal(buf, offset + 124, 12);
    const typeFlagByte = buf[offset + 156];
    const typeFlag = typeFlagByte === 0 ? '0' : String.fromCharCode(typeFlagByte);
    const prefix = readString(buf, offset + 345, 155);

    offset += BLOCK_SIZE;

    // File content follows immediately, padded to BLOCK_SIZE.
    const contentEnd = offset + size;
    const paddedEnd = offset + Math.ceil(size / BLOCK_SIZE) * BLOCK_SIZE;

    if (typeFlag === 'L') {
      // GNU longlink: the "content" is the real name for the NEXT entry.
      longName = readString(buf, offset, size).replace(/\0+$/, '');
      offset = paddedEnd;
      continue;
    }

    if (typeFlag === '0') {
      const fullName = longName ?? (prefix ? `${prefix}/${name}` : name);
      entries.push({
        name: fullName,
        bytes: buf.slice(offset, contentEnd),
      });
      longName = null;
    }
    // Any other type (directory '5', symlink '2', etc.) is silently skipped.

    offset = paddedEnd;
  }

  return entries;
}
