import type { Pane, RuleResult } from './base';
import { displayPath } from './base';

/** List pane — renders matches as a compact table. */
export function createListPane(id: string): Pane {
  let container: HTMLElement | null = null;

  return {
    id,
    mount(el) {
      container = el;
      container.className = 'pane pane-list';
    },
    update(result: RuleResult) {
      if (!container) return;
      while (container.firstChild) container.removeChild(container.firstChild);

      const title = document.createElement('div');
      title.className = 'pane-title';
      title.textContent = result.decls.title || result.rule.selector;
      container.append(title);

      if (result.matches.length === 0) {
        const empty = document.createElement('div');
        empty.className = 'pane-empty';
        empty.textContent = 'No matches.';
        container.append(empty);
        return;
      }

      const table = document.createElement('table');
      const thead = document.createElement('thead');
      const headerRow = document.createElement('tr');
      for (const col of ['name', 'type', 'file', 'line']) {
        const th = document.createElement('th');
        th.textContent = col;
        headerRow.append(th);
      }
      thead.append(headerRow);
      table.append(thead);

      const tbody = document.createElement('tbody');
      const limit = result.decls.limit ?? result.matches.length;
      for (const match of result.matches.slice(0, limit)) {
        const tr = document.createElement('tr');
        const tdName = document.createElement('td');
        tdName.textContent = match.name ?? '';
        const tdType = document.createElement('td');
        tdType.textContent = match.type;
        tdType.className = 'muted';
        const tdFile = document.createElement('td');
        tdFile.textContent = displayPath(match.file_path);
        tdFile.className = 'path';
        tdFile.title = match.file_path;
        const tdLine = document.createElement('td');
        tdLine.textContent = String(match.start_line);
        tr.append(tdName, tdType, tdFile, tdLine);
        tbody.append(tr);
      }
      table.append(tbody);
      container.append(table);
    },
    destroy() {
      if (container) while (container.firstChild) container.removeChild(container.firstChild);
      container = null;
    },
  };
}
