import type { Pane } from './base';
import type { RuleResult } from './base';
import { displayPath } from './base';

/** Context pane — small fixed-height card for one match's enclosing scope. */
export function createContextPane(id: string): Pane {
  let container: HTMLElement | null = null;

  return {
    id,
    mount(el) {
      container = el;
      container.className = 'pane pane-context';
    },
    update(result: RuleResult) {
      if (!container) return;
      while (container.firstChild) container.removeChild(container.firstChild);

      const title = document.createElement('div');
      title.className = 'pane-title';
      title.textContent = result.decls.title || result.rule.selector;
      container.append(title);

      if (result.matches.length === 0) {
        const empty = document.createElement('div');
        empty.className = 'pane-empty';
        empty.textContent = 'No match.';
        container.append(empty);
        return;
      }

      const match = result.matches[0];

      const header = document.createElement('div');
      header.className = 'context-header';
      header.textContent = `${displayPath(match.file_path)}:${match.start_line}-${match.end_line}`;
      if (match.qualified_name) {
        const qn = document.createElement('span');
        qn.className = 'context-qn';
        qn.textContent = `  ${match.qualified_name}`;
        header.append(qn);
      }
      container.append(header);

      const body = document.createElement('pre');
      body.className = 'context-body';
      body.textContent = match.peek ?? `(${match.type} at line ${match.start_line})`;
      container.append(body);

      if (result.matches.length > 1) {
        const more = document.createElement('div');
        more.className = 'context-more';
        more.textContent = `+ ${result.matches.length - 1} more match${result.matches.length === 2 ? '' : 'es'}`;
        container.append(more);
      }
    },
    destroy() {
      if (container) while (container.firstChild) container.removeChild(container.firstChild);
      container = null;
    },
  };
}
