// ── Theme system ────────────────────────────────────────────────────

export const THEMES = ['tokyo', 'gruvbox', 'dracula', 'cyberpunk', 'latte'] as const;
export type ThemeName = (typeof THEMES)[number];

function getStoredTheme(): ThemeName {
  const stored = localStorage.getItem('ast-css-theme') as ThemeName | null;
  return stored && THEMES.includes(stored) ? stored : 'tokyo';
}

function applyTheme(name: ThemeName): void {
  if (name === 'tokyo') {
    document.documentElement.removeAttribute('data-theme');
  } else {
    document.documentElement.setAttribute('data-theme', name);
  }
  localStorage.setItem('ast-css-theme', name);
}

function nextTheme(current: ThemeName): ThemeName {
  const idx = THEMES.indexOf(current);
  return THEMES[(idx + 1) % THEMES.length];
}

