import { inflate } from 'pako';
import JSZip from 'jszip';
import { untar } from '../lib/untar';
import type { TarEntry } from '../lib/untar';
import type { DuckDBHandle } from './duckdb';

export interface ParsedRepo {
  owner: string;
  repo: string;
  ref: string | undefined;
}

const HTTPS_RE =
  /^https:\/\/github\.com\/([^/]+)\/([^/]+?)(?:\.git)?(?:\/tree\/([^/]+))?\/?$/;
const SHORTHAND_RE = /^([^/\s]+)\/([^/\s@]+)(?:@([^\s]+))?$/;

export function parseRepoUrl(input: string): ParsedRepo {
  const trimmed = input.trim();
  if (!trimmed) {
    throw new Error('Invalid repo input: empty string');
  }

  if (trimmed.startsWith('http://') || trimmed.startsWith('https://')) {
    if (!trimmed.startsWith('https://github.com/')) {
      throw new Error(
        `Invalid repo input: only github.com URLs are supported (got ${trimmed})`
      );
    }
    const m = trimmed.match(HTTPS_RE);
    if (!m) {
      throw new Error(`Invalid github.com URL: ${trimmed}`);
    }
    return {
      owner: m[1],
      repo: m[2],
      ref: m[3] ?? undefined,
    };
  }

  const m = trimmed.match(SHORTHAND_RE);
  if (!m) {
    throw new Error(`Invalid repo input: ${trimmed}`);
  }
  return {
    owner: m[1],
    repo: m[2],
    ref: m[3] ?? undefined,
  };
}

export async function fetchTarball(parsed: ParsedRepo): Promise<Uint8Array> {
  const ref = parsed.ref ?? 'HEAD';
  const url = `/github-api/repos/${encodeURIComponent(parsed.owner)}/${encodeURIComponent(parsed.repo)}/tarball/${encodeURIComponent(ref)}`;

  const res = await fetch(url, {
    headers: {
      Accept: 'application/vnd.github+json',
      'X-GitHub-Api-Version': '2022-11-28',
    },
  });

  if (!res.ok) {
    if (res.status === 403) {
      throw new Error(
        `GitHub API rate limited (403). Try again in ~1 hour or add a token.`
      );
    }
    if (res.status === 404) {
      throw new Error(
        `Repo not found: ${parsed.owner}/${parsed.repo}@${ref}. Is it public?`
      );
    }
    throw new Error(`Failed to fetch tarball: HTTP ${res.status}`);
  }

  const buf = new Uint8Array(await res.arrayBuffer());
  if (buf.length === 0) {
    throw new Error('GitHub returned an empty tarball');
  }
  return buf;
}

// ── Shared filtering ────────────────────────────────────────────────

const MAX_FILE_BYTES = 1 * 1024 * 1024; // 1 MiB

const BINARY_EXTENSIONS = new Set([
  'png', 'jpg', 'jpeg', 'gif', 'webp', 'ico', 'bmp', 'tiff',
  'mp3', 'mp4', 'wav', 'flac', 'ogg', 'webm',
  'zip', 'gz', 'tgz', 'bz2', 'xz', '7z', 'rar', 'tar',
  'wasm', 'so', 'dll', 'dylib', 'o', 'a',
  'pdf', 'woff', 'woff2', 'ttf', 'otf', 'eot',
  'class', 'jar', 'pyc', 'pyo',
]);

export interface RepoEntry {
  path: string;
  bytes: Uint8Array;
}

function stripTarballPrefix(name: string): string | null {
  const slash = name.indexOf('/');
  if (slash < 0) return null;
  return name.slice(slash + 1);
}

function extOf(path: string): string {
  const dot = path.lastIndexOf('.');
  if (dot < 0 || dot === path.length - 1) return '';
  return path.slice(dot + 1).toLowerCase();
}

function entryIsBinary(path: string): boolean {
  return BINARY_EXTENSIONS.has(extOf(path));
}

function shouldKeep(path: string, size: number, globRe: RegExp | null): boolean {
  if (!path || path.length === 0) return false;
  if (size > MAX_FILE_BYTES) return false;
  if (entryIsBinary(path)) return false;
  if (globRe && !globRe.test(path)) return false;
  return true;
}

export function globToRegExp(glob: string): RegExp {
  let src = '';
  let i = 0;
  while (i < glob.length) {
    const c = glob[i];
    if (c === '*') {
      if (glob[i + 1] === '*') {
        if (glob[i + 2] === '/') {
          src += '(?:.*/)?';
          i += 3;
        } else {
          src += '.*';
          i += 2;
        }
      } else {
        src += '[^/]*';
        i += 1;
      }
    } else if (c === '?') {
      src += '[^/]';
      i += 1;
    } else if ('.()[]{}+|^$\\'.includes(c)) {
      src += '\\' + c;
      i += 1;
    } else {
      src += c;
      i += 1;
    }
  }
  return new RegExp('^' + src + '$');
}

// ── Extraction functions ────────────────────────────────────────────

/** Extract and filter entries from a gzipped tarball. */
export function extractTarballEntries(
  gzBytes: Uint8Array,
  glob?: string
): RepoEntry[] {
  const rawTar = inflate(gzBytes);
  const tarEntries: TarEntry[] = untar(rawTar);
  const globRe = glob ? globToRegExp(glob) : null;

  const out: RepoEntry[] = [];
  for (const e of tarEntries) {
    const rel = stripTarballPrefix(e.name);
    if (rel && shouldKeep(rel, e.bytes.length, globRe)) {
      out.push({ path: rel, bytes: e.bytes });
    }
  }
  return out;
}

/** Extract and filter entries from a zip file. */
export async function extractZipEntries(
  zipBytes: ArrayBuffer,
  glob?: string
): Promise<RepoEntry[]> {
  const zip = await JSZip.loadAsync(zipBytes);
  const globRe = glob ? globToRegExp(glob) : null;
  const out: RepoEntry[] = [];

  const filePromises: Promise<void>[] = [];
  zip.forEach((relativePath, file) => {
    if (file.dir) return;
    // Zip archives may also have a top-level directory; strip it.
    const rel = stripTarballPrefix(relativePath);
    if (!rel) return;
    filePromises.push(
      file.async('uint8array').then((bytes) => {
        if (shouldKeep(rel, bytes.length, globRe)) {
          out.push({ path: rel, bytes });
        }
      })
    );
  });
  await Promise.all(filePromises);
  return out;
}

/** Fetch a GitHub repo tarball and extract entries. Dev-mode convenience. */
export async function fetchAndExtractRepo(
  parsed: ParsedRepo,
  glob?: string
): Promise<RepoEntry[]> {
  const gz = await fetchTarball(parsed);
  return extractTarballEntries(gz, glob);
}

// ── VFS registration ────────────────────────────────────────────────

export interface RegisteredRepo {
  owner: string;
  repo: string;
  ref: string;
  vfsPrefix: string;
  fileCount: number;
}

export async function registerEntries(
  handle: DuckDBHandle,
  vfsPrefix: string,
  entries: RepoEntry[]
): Promise<RegisteredRepo> {
  for (const entry of entries) {
    const vfsPath = `${vfsPrefix}/${entry.path}`;
    await handle.db.registerFileBuffer(vfsPath, entry.bytes);
  }
  const parts = vfsPrefix.split('/');
  return {
    owner: parts[0] ?? 'upload',
    repo: parts[1] ?? 'unnamed',
    ref: 'HEAD',
    vfsPrefix,
    fileCount: entries.length,
  };
}

export async function registerRepo(
  handle: DuckDBHandle,
  parsed: ParsedRepo,
  entries: RepoEntry[]
): Promise<RegisteredRepo> {
  const vfsPrefix = `${parsed.owner}/${parsed.repo}`;
  return registerEntries(handle, vfsPrefix, entries);
}
