export interface PSSRule {
  id: string;
  selector: string;
  declarations: Record<string, string>;
}

function hashString(s: string): string {
  let h = 0;
  for (let i = 0; i < s.length; i++) {
    h = ((h << 5) - h + s.charCodeAt(i)) | 0;
  }
  return (h >>> 0).toString(36);
}

function stripComments(input: string): string {
  return input.replace(/\/\*[\s\S]*?\*\//g, '');
}

function parseDeclarations(block: string): Record<string, string> {
  const decls: Record<string, string> = {};
  const parts = block.split(';').map((s) => s.trim()).filter(Boolean);
  for (const part of parts) {
    const colonIdx = part.indexOf(':');
    if (colonIdx < 0) continue;
    const key = part.slice(0, colonIdx).trim().toLowerCase();
    let value = part.slice(colonIdx + 1).trim();
    if ((value.startsWith('"') && value.endsWith('"')) ||
        (value.startsWith("'") && value.endsWith("'"))) {
      value = value.slice(1, -1);
    }
    if (key) decls[key] = value;
  }
  return decls;
}

function findClosingBrace(input: string, start: number): number {
  let depth = 0;
  for (let i = start; i < input.length; i++) {
    if (input[i] === '{') depth++;
    else if (input[i] === '}') {
      depth--;
      if (depth === 0) return i;
    }
  }
  return -1;
}

export function parsePSS(input: string): PSSRule[] {
  const cleaned = stripComments(input).trim();
  if (!cleaned) return [];

  const rules: PSSRule[] = [];
  let pos = 0;

  while (pos < cleaned.length) {
    while (pos < cleaned.length && /\s/.test(cleaned[pos])) pos++;
    if (pos >= cleaned.length) break;

    const braceIdx = cleaned.indexOf('{', pos);

    if (braceIdx < 0) {
      const selector = cleaned.slice(pos).trim();
      if (selector) {
        rules.push({ id: hashString(`${selector}{}`), selector, declarations: {} });
      }
      break;
    }

    const selector = cleaned.slice(pos, braceIdx).trim();
    const closeIdx = findClosingBrace(cleaned, braceIdx);

    if (closeIdx < 0) {
      if (selector) {
        rules.push({ id: hashString(`${selector}{}`), selector, declarations: {} });
      }
      break;
    }

    const blockContent = cleaned.slice(braceIdx + 1, closeIdx);
    const declarations = parseDeclarations(blockContent);
    const canonical = `${selector}{${Object.entries(declarations).sort().map(([k, v]) => `${k}:${v}`).join(';')}}`;

    if (selector) {
      rules.push({ id: hashString(canonical), selector, declarations });
    }

    pos = closeIdx + 1;
  }

  return rules;
}
