import * as duckdb from '@duckdb/duckdb-wasm';

export interface DuckDBHandle {
  db: duckdb.AsyncDuckDB;
  conn: duckdb.AsyncDuckDBConnection;
  extensionLoaded: boolean;
}

// Community-extensions CDN hosts signed WASM builds for every DuckDB release.
// Bump this when upgrading @duckdb/duckdb-wasm to a newer engine.
const DUCKDB_ENGINE_VERSION = 'v1.5.2';

/**
 * Override the extension URL at build time. Lets a deployment point at a
 * locally-bundled .wasm when the community CDN hasn't published the fix/version
 * we need. Set via `VITE_EXTENSION_URL` — absolute URL or site-relative path.
 */
const EXTENSION_URL_OVERRIDE = import.meta.env.VITE_EXTENSION_URL;

/**
 * Infer which WASM platform duckdb-wasm selected so we fetch the matching
 * extension binary (mvp / eh / threads have different WASM ABIs).
 */
function extensionPlatform(bundle: duckdb.DuckDBBundle): string {
  const worker = bundle.mainWorker ?? '';
  if (worker.includes('coi')) return 'wasm_threads';
  if (worker.includes('-eh')) return 'wasm_eh';
  return 'wasm_mvp';
}

/**
 * Boot duckdb-wasm using the jsDelivr bundle. Returns a connected database.
 * Community extensions are signed, so allowUnsignedExtensions is off.
 */
export async function initDuckDB(): Promise<DuckDBHandle & { platform: string }> {
  const bundles = duckdb.getJsDelivrBundles();
  const bundle = await duckdb.selectBundle(bundles);
  const platform = extensionPlatform(bundle);

  const workerUrl = URL.createObjectURL(
    new Blob([`importScripts("${bundle.mainWorker!}");`], {
      type: 'text/javascript',
    })
  );
  const worker = new Worker(workerUrl);
  const logger = new duckdb.ConsoleLogger();
  const db = new duckdb.AsyncDuckDB(logger, worker);
  await db.instantiate(bundle.mainModule, bundle.pthreadWorker);
  URL.revokeObjectURL(workerUrl);

  await db.open({});

  const conn = await db.connect();

  // Chrome caps WASM instances at ~3GB. 2GB leaves headroom for tree-sitter
  // parses, result serialization, and VFS bytes.
  await conn.query(`PRAGMA memory_limit='2GB'`);

  return { db, conn, extensionLoaded: false, platform };
}

/**
 * Load sitting_duck from the community-extensions CDN.
 *
 * The CDN serves CORS-enabled, signed WASM extension binaries at:
 *   community-extensions.duckdb.org/{version}/{platform}/{name}.duckdb_extension.wasm
 *
 * DuckDB-WASM's LOAD with an absolute URL XHRs the binary directly — no
 * repository discovery or INSTALL step needed.
 */
export async function loadSittingDuck(
  handle: DuckDBHandle & { platform: string }
): Promise<void> {
  if (handle.extensionLoaded) return;

  const cdnUrl =
    `https://community-extensions.duckdb.org/${DUCKDB_ENGINE_VERSION}` +
    `/${handle.platform}/sitting_duck.duckdb_extension.wasm`;

  // If the override is site-relative (starts with `/` or a bare filename),
  // resolve against the page origin so duckdb-wasm's worker can XHR it.
  let extensionUrl = EXTENSION_URL_OVERRIDE || cdnUrl;
  if (extensionUrl.startsWith('/') && globalThis.location?.origin) {
    extensionUrl = globalThis.location.origin + extensionUrl;
  }

  // Verify the binary is reachable before handing it to DuckDB's loader.
  const probe = await fetch(extensionUrl, { method: 'HEAD' });
  if (!probe.ok) {
    throw new Error(
      `Failed to reach sitting_duck extension at ${extensionUrl}: HTTP ${probe.status}.`
    );
  }

  await handle.conn.query(`LOAD '${extensionUrl}'`);

  // Sanity probe — ast_type_map returns node-type info for any supported language.
  const sanity = await handle.conn.query(
    "SELECT count(*) AS n FROM ast_type_map('python')"
  );
  const n = Number(sanity.toArray()[0].n);
  if (n === 0) {
    throw new Error(
      'sitting_duck loaded but ast_type_map returned 0 rows for python.'
    );
  }

  handle.extensionLoaded = true;
}
