import type { Pane, AstMatch } from './base';
import { displayPath } from './base';

/**
 * Synthetic editable widget — renders each match as an editable <textarea>
 * seeded with the match's source text. Edits are session-local and never
 * persisted back to the repo. "Synthetic" = a scratchpad, not a real editor.
 *
 * Session state: we keep each match's edited text in a Map keyed by a stable
 * (file_path, start_line, end_line) tuple so that re-running the same query
 * preserves in-progress edits. Stored on the pane instance (lost on destroy).
 */
export function createEditPane(id: string): Pane {
  let container: HTMLElement | null = null;
  // Session edits: key = file_path|start_line|end_line
  const edits = new Map<string, string>();

  function editKey(m: AstMatch): string {
    return `${m.file_path}|${m.start_line}|${m.end_line}`;
  }

  return {
    id,
    mount(el) {
      container = el;
      container.className = 'pane pane-edit';
    },
    update(result) {
      if (!container) return;
      while (container.firstChild) container.removeChild(container.firstChild);

      const title = document.createElement('div');
      title.className = 'pane-title';
      title.textContent = result.decls.title || `${result.rule.selector} (editable)`;
      container.append(title);

      if (result.matches.length === 0) {
        const empty = document.createElement('div');
        empty.className = 'pane-empty';
        empty.textContent = 'No matches to edit.';
        container.append(empty);
        return;
      }

      const limit = result.decls.limit ?? result.matches.length;
      for (const match of result.matches.slice(0, limit)) {
        const region = document.createElement('div');
        region.className = 'edit-region';

        const header = document.createElement('div');
        header.className = 'edit-header';
        const path = displayPath(match.file_path);
        const lines = match.start_line === match.end_line
          ? String(match.start_line)
          : `${match.start_line}-${match.end_line}`;
        header.textContent = `${path}:${lines}`;
        if (match.name) {
          const nameSpan = document.createElement('span');
          nameSpan.className = 'edit-name';
          nameSpan.textContent = `  ${match.name}`;
          header.append(nameSpan);
        }

        const dirtyBadge = document.createElement('span');
        dirtyBadge.className = 'edit-dirty';
        dirtyBadge.textContent = ' · edited';
        dirtyBadge.style.display = 'none';
        header.append(dirtyBadge);

        const originalText = match.peek ?? `(${match.type} at line ${match.start_line})`;
        const key = editKey(match);
        const currentText = edits.has(key) ? edits.get(key)! : originalText;

        const textarea = document.createElement('textarea');
        textarea.className = 'edit-body';
        textarea.value = currentText;
        textarea.spellcheck = false;
        // Auto-size to the number of lines (capped to 40 rows)
        const lineCount = Math.min(currentText.split('\n').length, 40);
        textarea.rows = Math.max(lineCount, 3);

        if (edits.has(key) && edits.get(key) !== originalText) {
          dirtyBadge.style.display = 'inline';
        }

        textarea.addEventListener('input', () => {
          edits.set(key, textarea.value);
          dirtyBadge.style.display = textarea.value !== originalText ? 'inline' : 'none';
        });

        region.append(header, textarea);
        container.append(region);
      }

      // Footer with a note that edits are synthetic
      const footer = document.createElement('div');
      footer.className = 'edit-footer';
      footer.textContent = 'Synthetic edits — session-local, not written back to files.';
      container.append(footer);
    },
    destroy() {
      if (container) while (container.firstChild) container.removeChild(container.firstChild);
      container = null;
      edits.clear();
    },
  };
}
